INSERT INTO articles (title, slug, content, summary, category_id, view_count, comment_count, status, is_top, reading_time, created_at, updated_at) VALUES
('2025年个人技术年度总结', '2025-tech-annual-summary', '2025年即将结束，回顾这一年的技术成长和收获。深入学习了Go语言并发编程，掌握了Kubernetes容器编排，学习了Rust系统编程。完成了博客系统重构，开源了多个工具库。', '2025年个人技术成长总结，包括技术学习、项目成果和未来规划。', 2, 523, 15, 'published', false, 15, '2025-12-28 10:00:00', '2025-12-28 10:00:00'),
('使用 Docker Compose 部署个人博客', 'docker-compose-blog-deployment', '使用 Docker Compose 部署个人博客，实现一键部署和迁移。技术栈包括Nginx反向代理、MySQL数据库、Redis缓存、Go后端服务。', '使用 Docker Compose 一键部署个人博客的完整指南。', 1, 389, 8, 'published', false, 8, '2025-11-15 14:30:00', '2025-11-15 14:30:00'),
('Go 语言高性能 Web 服务实践', 'go-high-performance-web', '分享在 Go 语言中构建高性能 Web 服务的经验。包括连接池管理、缓存策略、并发处理等优化策略。经过优化，QPS提升了300%。', 'Go 语言构建高性能 Web 服务的实践经验和优化策略。', 2, 267, 6, 'published', false, 12, '2025-10-20 09:15:00', '2025-10-20 09:15:00'),
('周末徒步：秦岭深处的宁静', 'weekend-hiking-qinling', '周末和朋友一起徒步秦岭，远离城市喧嚣。沿途风景有茂密的森林、清澈的溪流、连绵的山峦。在大自然中，所有的烦恼都变得渺小。', '周末徒步秦岭的旅行记录和感悟。', 3, 156, 4, 'published', false, 7, '2025-09-08 18:45:00', '2025-09-08 18:45:00'),
('AI 编程助手使用心得', 'ai-programming-assistant-tips', '使用 AI 编程助手半年的心得体会。推荐工具包括GitHub Copilot、Cursor、Claude Code。编码效率提升约40%，但需要保持警惕。', 'AI 编程助手的使用心得和效率提升经验。', 2, 412, 10, 'published', false, 9, '2025-08-12 11:20:00', '2025-08-12 11:20:00'),
('从零开始学习 Kubernetes', 'learning-kubernetes-from-scratch', '容器化已成为主流，K8s是容器编排的事实标准。学习路径包括Docker基础、K8s核心概念、动手实践。部署了一个微服务架构的博客系统。', 'Kubernetes 从入门到实践的学习指南。', 2, 298, 7, 'published', false, 18, '2025-07-05 16:00:00', '2025-07-05 16:00:00'),
('读书笔记：《深入理解计算机系统》', 'book-review-CSAPP', 'CSAPP是计算机科学的经典教材。重点内容包括信息的表示、程序的机器级表示、处理器体系结构。这本书让我对计算机系统有了更深入的理解。', '《深入理解计算机系统》读书笔记和感悟。', 2, 189, 5, 'published', false, 20, '2025-06-18 20:30:00', '2025-06-18 20:30:00'),
('我的 NAS 搭建历程', 'my-nas-setup-journey', '需要一个私有云存储来备份照片和文档。硬件选择Intel N5105、16GB内存、4TB x2硬盘。最终选择了TrueNAS Scale。', '个人 NAS 搭建过程和使用经验分享。', 1, 345, 9, 'published', false, 11, '2025-05-22 13:40:00', '2025-05-22 13:40:00'),
('程序员的健康生活', 'programmer-healthy-lifestyle', '久坐、熬夜、颈椎病是程序员的常见问题。解决方案包括运动、饮食、作息调整。坚持三个月，身体状态明显改善。', '程序员保持健康生活方式的建议和经验。', 3, 278, 12, 'published', false, 6, '2025-04-10 08:25:00', '2025-04-10 08:25:00'),
('Redis 缓存实战：从入门到精通', 'redis-cache-practice', 'Redis是一个高性能的内存数据库。使用场景包括缓存热点数据、会话存储、消息队列。实战经验包括缓存穿透、雪崩、击穿的解决方案。', 'Redis 缓存使用实战经验和常见问题解决方案。', 2, 356, 8, 'published', false, 14, '2025-03-15 10:50:00', '2025-03-15 10:50:00');
INSERT INTO articles (title, slug, content, summary, category_id, view_count, comment_count, status, is_top, reading_time, created_at, updated_at) VALUES
('2024年年终总结：成长与收获', '2024-annual-summary', '2024年是充满挑战和收获的一年。完成了多个重要项目，技术能力显著提升。深入学习了分布式系统，掌握了云原生技术。', '2024 年个人成长总结，包括工作、学习和生活。', 3, 678, 22, 'published', false, 16, '2024-12-30 09:00:00', '2024-12-30 09:00:00'),
('Gin 框架实战：构建 RESTful API', 'gin-framework-restful-api', 'Gin是一个高性能的Go Web框架。项目结构清晰，包含路由、处理器、服务、仓储层。核心功能包括路由管理、中间件、参数绑定、错误处理。', '使用 Gin 框架构建 RESTful API 的完整指南。', 2, 534, 14, 'published', false, 13, '2024-11-25 15:30:00', '2024-11-25 15:30:00'),
('Git 工作流：团队协作的最佳实践', 'git-workflow-best-practices', '常见工作流包括Git Flow、GitHub Flow、GitLab Flow。提交规范使用feat、fix、docs等前缀。Code Review要及时响应，保持礼貌。', 'Git 团队协作工作流和最佳实践指南。', 2, 423, 11, 'published', false, 10, '2024-10-18 11:45:00', '2024-10-18 11:45:00'),
('周末烘焙：第一次做蛋糕', 'weekend-baking-first-cake', '看到朋友圈的蛋糕照片，决定自己尝试。准备了鸡蛋、面粉、糖、牛奶等材料。虽然卖相一般，但味道还不错！', '第一次尝试烘焙蛋糕的经历和心得。', 3, 198, 8, 'published', false, 5, '2024-09-12 17:20:00', '2024-09-12 17:20:00'),
('MySQL 性能优化实战', 'mysql-performance-optimization', '线上数据库查询变慢，需要优化。通过慢查询日志、EXPLAIN分析找出问题。优化方案包括索引优化、查询优化、表结构优化。查询时间从2s降低到50ms。', 'MySQL 数据库性能优化的实战经验和技巧。', 2, 467, 13, 'published', false, 15, '2024-08-20 14:10:00', '2024-08-20 14:10:00'),
('我的 2024 阅读清单', 'my-2024-reading-list', '2024年计划阅读24本书，实际阅读了28本。推荐书籍包括《深入理解计算机系统》《设计模式》《人类简史》《思考，快与慢》等。', '2024 年度阅读清单和读书心得分享。', 3, 312, 9, 'published', false, 8, '2024-07-15 20:00:00', '2024-07-15 20:00:00'),
('Docker 入门到实践', 'docker-getting-started', 'Docker的核心概念包括镜像、容器、仓库。常用命令包括pull、run、ps、logs等。使用Docker部署了个人博客。', 'Docker 从入门到实践的完整学习指南。', 2, 589, 16, 'published', false, 11, '2024-06-08 10:30:00', '2024-06-08 10:30:00'),
('旅行：厦门三日游', 'xiamen-three-days-trip', 'Day1游览鼓浪屿和南普陀寺，Day2参观厦门大学和曾厝垵，Day3环岛路骑行和中山路购物。推荐美食有沙茶面、海蛎煎、土笋冻。', '厦门三日游的旅行攻略和游记。', 3, 267, 7, 'published', false, 9, '2024-05-02 16:45:00', '2024-05-02 16:45:00'),
('Go 语言错误处理最佳实践', 'go-error-handling-best-practices', 'Go语言没有异常机制，错误处理需要特别注意。常见方式包括直接返回、包装错误、自定义错误。最佳实践是不要忽略错误，提供上下文信息。', 'Go 语言错误处理的常见方式和最佳实践。', 2, 398, 10, 'published', false, 7, '2024-04-10 09:20:00', '2024-04-10 09:20:00'),
('新手如何搭建个人博客', 'how-to-build-personal-blog', '博客可以记录学习笔记、分享技术经验、建立个人品牌。技术选型包括Hugo、Hexo、WordPress等。我选择了自建博客，使用Go+Vue。', '从零开始搭建个人博客的完整指南。', 1, 623, 18, 'published', true, 14, '2024-03-15 11:00:00', '2024-03-15 11:00:00');
